   160	    public static func stripWhisperMarkers(_ text: String) -> String {
   161	        let nsText = text as NSString
   162	        let matches = markerRegex.matches(in: text, range: NSRange(location: 0, length: nsText.length))
   163	        var result = text
   164	        for match in matches.reversed() {
   165	            let innerRange = match.range(at: 1)
   166	            let inner = nsText.substring(with: innerRange)
   167	            if knownMarkers.contains(inner), let fullRange = Range(match.range, in: result) {
   168	                result.replaceSubrange(fullRange, with: "")
   169	            }
   170	        }
   171	        return result
   172	            .replacingOccurrences(of: "\\s+", with: " ", options: .regularExpression)
   173	            .trimmingCharacters(in: .whitespacesAndNewlines)
   174	    }
