   179	            .replacingOccurrences(of: "\\s+", with: " ", options: .regularExpression)
   180	            .trimmingCharacters(in: .whitespacesAndNewlines)
   181	        guard !cleaned.isEmpty else { return nil }
   182	        if cleaned.count <= maxPromptCharacters {
   183	            return cleaned
   184	        }
   185	        let start = cleaned.index(cleaned.endIndex, offsetBy: -maxPromptCharacters)
   186	        return String(cleaned[start...]).trimmingCharacters(in: .whitespacesAndNewlines)
   187	    }
